original_creation_snippet:
export const BranchService = {
    async create(input, deps) {
        const branch = await deps.executor.branch.create({ data: input });
        await deps.executor.branchSettings.create({ data: { branchId: branch.id, theme: 'default' } });
        return branch;
    },
};
